const startedAt=new Date().toISOString();
const missingVars=[];
if(!$env.TELEGRAM_BOT_TOKEN)missingVars.push("TELEGRAM_BOT_TOKEN");
if(!$env.TELEGRAM_CHAT_ID)missingVars.push("TELEGRAM_CHAT_ID");
if(!$env.DASHBOARD_API_KEY)missingVars.push("DASHBOARD_API_KEY");
if(missingVars.length>0)throw new Error("Pre-hook FAIL: "+missingVars.join(", "));
const out={startedAt,contextOk:true,workflow:"lead-pipeline-health"};
return[{json:out}];

const ctx=$("Pre-Hook: Valida Contesto").first().json;
const snap=$input.first().json;
const endedAt=new Date().toISOString();
const durationMs=new Date(endedAt)-new Date(ctx.startedAt);
const auto=snap.automation||{};
const stats=auto.stats||{};
const weekly=stats.weekly||{};
const pendingRatio=typeof auto.pendingRatio==="number"?auto.pendingRatio:null;
const pendingCount=auto.pendingCount||weekly.pending||null;
const invitesLast2d=weekly.invitesSentLast2d||null;
const invitesLast7d=weekly.invitesSent||0;
const acceptedLast7d=weekly.invitesAccepted||0;
const acceptanceRate7d=invitesLast7d>0?((acceptedLast7d/invitesLast7d)*100).toFixed(1):null;
const riskAction=auto.riskAction||"UNKNOWN";
const alerts=[];
if(pendingCount!==null&&pendingCount>50){alerts.push("⚠️ Troppi pending: "+pendingCount+" > 50 → rallenta gli inviti");}
if(invitesLast2d!==null&&invitesLast2d===0){alerts.push("⚠️ Bot inattivo? 0 inviti negli ultimi 2 giorni");}
if(riskAction==="STOP"||riskAction==="WARN"){alerts.push("🛑 Risk action: "+riskAction+" → verifica account");}
const hasAlerts=alerts.length>0;
const out={snap:auto,pendingRatio,pendingCount,invitesLast7d,acceptedLast7d,acceptanceRate7d,invitesLast2d,riskAction,alerts,hasAlerts,startedAt:ctx.startedAt,endedAt,durationMs};
return[{json:out}];

const data=$input.first().json;
const now=new Date();
const dateStr=now.toLocaleDateString("it-IT",{day:"2-digit",month:"2-digit",year:"numeric"});
const lines=["📈 *Lead Pipeline Health — "+dateStr+"*",""];
lines.push("*Ultimi 7 giorni:*");
lines.push("  Inviti inviati: "+(data.invitesLast7d||"n/d"));
lines.push("  Inviti accettati: "+(data.acceptedLast7d||"n/d")+" ("+( data.acceptanceRate7d||"n/d")+"%)");
lines.push("  Pending totali: "+(data.pendingCount||"n/d"));
lines.push("  Risk action: "+(data.riskAction||"n/d"));
if(data.alerts.length>0){lines.push("");lines.push("*🚨 Alert:*");data.alerts.forEach(a=>lines.push("  "+a));}
lines.push("");lines.push("_Durata: "+data.durationMs+"ms_");
const out={report:lines.join("
"),hasAlerts:data.hasAlerts,alertCount:data.alerts.length,startedAt:data.startedAt,endedAt:data.endedAt,durationMs:data.durationMs};
return[{json:out}];

